// export default Home


import React from 'react';

const Home = () => {
    return (
        <>
            <div className='main-heading'>
                Welcome to your world — where it gets the attention it quietly deserves.
            </div>

            <div className='main-menu'>
                <div className='menu-box'>Journal</div>
                <div className='menu-box'>Mood</div>
                <div className='menu-box'>Tasks</div>
                <div className='menu-box'>Dashboard</div>
            </div>

            <div className='design-layout'>
                <img className='design' src='/assets/background1.png' alt='decorative design' />
            </div>

            <div className='footer-heading'>
                DearDiary - Divya
            </div>

            <Stylesheet />
        </>
    );
};

const Stylesheet = () => {
    return (
        <style>{`
            .main-heading {
                position: absolute;
                top: 15%;
                width: 100%;
                text-align: center;
                font-size: 24px;
                font-weight: bold;
                color: var(--font-text, #333);
                padding: 0 20px;
            }

            .main-menu {
                display: flex;
                flex-direction: row;
                gap: 2%;
                height: 200px;
                width: 100%;
                align-items: center;
                justify-content: center;
                position: absolute;
                bottom: 40%;
            }

            .menu-box {
                background-color: var(--secondary-color, #fff);
                width: 150px;
                height: 80%;
                display: flex;
                align-items: center;
                justify-content: center;
                border-radius: 10px;
                transition: all 0.3s ease;
                font-size: 18px;
                font-weight: 500;
                cursor: pointer;
            }

            .menu-box:hover {
                transform: scale(1.05);
                box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
                background-color: var(--hover-color, #f3f3f3);
            }

            .design-layout {
                width: 100%;
                position: absolute;
                bottom: 21%;
                display: flex;
                align-items: center;
                justify-content: center;
            }

            .design {
                width: 80%;
                max-width: 500px;
                height: auto;
                opacity: 0.8;
            }

            .footer-heading {
                position: absolute;
                bottom: 10%;
                right: 30%;
                font-size: 30px;
                font-weight: 600;
                color: var(--font-text, #555);
            }
        `}</style>
    );
};

export default Home;
